import React from "react"
import styles from './HelloWorld.module.scss';

interface IAzureDataGrid {
  id: number;
  vehicle: string;
  lastService: string;
  nextService: string;
  status: string
}

export default function AzureFunctionDataGrid({dataGrid: IAzureDataGrid}) {
  return(
    <table className={styles['vehicle-table']}>
      <thead>
        <tr>
        <th>Make</th>
        <th>VIN</th>
        <th>Model</th>
        <th>Trim</th>
        <th>Price</th>
        <th></th>
        <th></th>
        </tr>
      </thead>
      <tbody>
        {
          dataGrid.map((item: IAzureDataGrid) => {
            return(
            <tr id={item.Id}>
              <td>{item.Make}</td>
              <td>{item.VIN}</td>
              <td>{item.Model}</td>
              <td>{item.Trim}</td>
              <td>{item.Price}</td>
              <td> <EditRegular style={{cursor: 'pointer'}} onClick={() => handleEdit(item.Id)}/> </td>
              <td> <DeleteRegular style={{cursor: 'pointer'}} onClick={() => handleDelete(item.Id)} /> </td>
            </tr>
            )
          })
        }
      </tbody>           
    </table>
  )
}